file-displayphoto-shrink_800_800/0/1638179788887?e=1778112000&v=beta&t=8ePXFer9cZ481p7bWkiY4A3rqa8abt5arWMFGhf6t2s", "peopleAlsoViewed/23/public_identifier": "etiennesibiodon", "peopleAlsoViewed/23/url": "https://linkedin.com/in/ACoAAAOWH10Bs90-LZZvr2rtavScSlBCk5ZWV24", "peopleAlsoViewed/24/entity_urn": "urn:li:fsd_profile:ACoAACNlCmEBdghyOYiBhnhHnm8KSkbEuvr7xgI", "peopleAlsoViewed/24/first_name": "Karen", "peopleAlsoViewed/24/follower_count": "178", "peopleAlsoViewed/24/headline": "Casino controller at Venetian Macau Limited", "peopleAlsoViewed/24/last_name": "Chau", "peopleAlsoViewed/24/premium": "false", "peopleAlsoViewed/24/public_identifier": "karen-chau-429a54146", "peopleAlsoViewed/24/url": "https://linkedin.com/in/ACoAACNlCmEBdghyOYiBhnhHnm8KSkbEuvr7xgI", "peopleAlsoViewed/25/entity_urn": "urn:li:fsd_profile:ACoAAEzCeQwBiVqfNYeOxyvZQB7TRi06LQdeOOI", "peopleAlsoViewed/25/first_name": "Glawdys", "peopleAlsoViewed/25/follower_count": "106", "peopleAlsoViewed/25/headline": "Recherche alternance / Contrat de professionnalisation | Secrétaire médicale", "peopleAlsoViewed/25/last_name": "Hodiesne", "peopleAlsoViewed/25/premium": "false", "peopleAlsoViewed/25/profile_picture": "https://media.licdn.com/dms/image/v2/D4E03AQGzKwezztFT9g/profile-displayphoto-shrink_800_800/profile-displayphoto-shrink_800_800/0/1714728728272?e=1778112000&v=beta&t=wVtY6_5FCyWuqJ2dWyb2WOMN-ouhjasyVey5rz1Jo30", "peopleAlsoViewed/25/public_identifier": "glawdys-hodiesne-4643522bb", "peopleAlsoViewed/25/url": "https://linkedin.com/in/ACoAAEzCeQwBiVqfNYeOxyvZQB7TRi06LQdeOOI", "profilePic": "https://media.licdn.com/dms/image/v2/D5603AQEZa4SVbbyv0Q/profile-displayphoto-shrink_800_800/profile-displayphoto-shrink_800_800/0/1678882512438?e=1778112000&v=beta&t=2UmuP7OCUv6tfo-eg0S-wbP2lRHTRxoBQVSfKT_dMow", "profilePicHighQuality": "https://media.licdn.com/dms/image/v2/D5603AQEZa4SVbbyv0Q/profile-displayphoto-shrink_800_800/profile-displayphoto-shrink_800_800/0/1678882512438?e=1778112000&v=beta&t=2UmuP7OCUv6tfo-eg0S-wbP2lRHTRxoBQVSfKT_dMow", "publicIdentifier": "fabricedecotte", "recommendations/0/context": "Fabrice was Timothy's client", "recommendations/0/date": "October 12, 2021", "recommendations/0/description": "I had the pleasure of building a great supplier-client relationship with Timothy when I worked for Sands China Limited. I've know Timothy since his time at Summergate wines and Sands China remained a client of Timothy when he moved on to start-up Claret Wines. It was always a pleasure dealing with Tim because he puts people first and foremost as his modus-operandum. Tim has always been very approachable, flexible and nothing has ever been too much trouble for him. \nI had the opportunity to work with Timothy on many beverage programs such as mass-volume Wine-of-the-Month programs, very successful lifestyle events for our fine-dining venues, and also our weekly wine tasting events. Timothy also did many product training sessions for our Team Members to give the best knowledge, resulting in positive Sales results for both parties. \nOverall, Tim is the most pleasant customer-oriented sales person I've worked with; he is an extremely humble gentleman who develops nurturing and long lasting relationships with his clients without hidden agendas. These traits make him successful whether as a sales-person, an entrepreneur, or in any organization he choses to be part of. Anyone would be lucky to work with or alongside Timothy! ", "recommendations/0/name": "Timothy Feather DipWSET, AIWS", "recommendations/0/subtitle": "Head of Sales & Business Development at Vino Veritas Macau", "recommendations/0/url": "https://www.linkedin.com/in/timothyfeather/", "recommendations/0/urn": "urn:li:fsd_profile:ACoAAAOKG8wBTPhIcguKQeEc_5wmBqj6jOjR8M8", "recommendations/1/context": "Fabrice managed Chad directly", "recommendations/1/date": "March 10, 2020", "recommendations/1/description": "I had the pleasure of working with Chad at the Sands Macau. Chad was an exceptional leader for the culinary team where he displayed tremendous employee engagement that resulted in many improvements across culinary quality, employee productivity and financial management. Chad also championed continuous improvements through his dedication to talent development and attention to detail. His leadership, strong engagement and team work resulted in many awards and accolades for the property's fine dining restaurants. ", "recommendations/1/name": "Chad Ogden", "recommendations/1/subtitle": "Director of Food and Beverage Operations", "recommendations/1/url": "https://www.linkedin.com/in/chadogden/", "recommendations/1/urn": "urn:li:fsd_profile:ACoAAAo5UJABXVHOSEzyr9qcGlrw4HSBR7GwgPc", "recommendations/2/context": "Fabrice managed Shahie directly", "recommendations/2/date": "July 25, 2019", "recommendations/2/description": "I had the honor and privilege of recruiting Shahie to manage Copa Steakhouse at the Sands Macau casino hotel, and working with him. His quite demeanour and gentle personality made it easy to mentor him. Shahie took on a challenging role and drove the success of the operation through motivating and engaging his team, as well as developing a great relationship with his Chef de Cuisine. Shahie also developed close relationships with his guests, resulting in a high loyalty level of cash customers who only came in the property for Copa steakhouse, whether from Macau or Hong Kong. He was instrumental in driving the strong lifestyle programs that Copa was known for, with numerous wine and pairing dinners hosted by winemakers from all regions of the world. \nShahie's leadership and efforts led Copa steakhouse to command the profit margings in excess of 40 percent, as well as the highest average check in the entire Sands China Limited portfolio of restaurants; driven by his strong team engagement and sales program. No doubt that he stimulated Copa's numerous awards and recognitions during his tenure. \nI miss working with Shahie and never fail to pay him a visit when visiting Singapore. It's a joy to see his continued success and career progression. I would have no hesitation in recommending Shahie for further roles and promotions in time to come, as his skills and experience - along with his endeavour to seek continuous improvements - would be an asset to any organization. \n", "recommendations/2/name": "Shahie J", "recommendations/2/subtitle": "Luxury | Hospitality | Leader", "recommendations/2/url": "https://www.linkedin.com/in/shahie-j-72131571/", "recommendations/2/urn": "urn:li:fsd_profile:ACoAAA8sqskBk0bgoIaOBKV2_INqHxLI0id2qTg", "recommendations/3/context": "Fabrice was senior to L D but didn't manage L D directly", "recommendations/3/date": "December 29, 2018", "recommendations/3/description": "The executive chef and I had the pleasure of recruiting Luis for COPA Steakhouse in Macau, and working with him for 3 years. During Luis' tenure as Head Chef for COPA, he saw the transformation and repositioning of the restaurant to Macau's top restaurant as Ranked No. 1 on Trip Advisor, a rank that was held for quite some time. \n\nLuis culinary abilities, passion for cooking, customer care and skills are complimented by his positive attitude and gentle personality. He made a strong presence felt in the kitchen and restaurant by displaying his ability to mentor a talented young group of chefs, producing the quality of the food that was served, and building a great relationship with the outlet managers. \n\nI also had the pleasure of working very closely with Luis on putting together a calendar of food and wine-pairing lifestyle that helped to put COPA and the Sands Macau on the map in Macau. These events showcased Luis' ability to think outside the box and show his culinary creative genius. \n\nWith the positive and close relationship Luis nurtured with the restaurant manager, there was little surprise about the number of Awards and Recognitions achieved by the COPA Team! \n\nI have maintained close contact with Luis since he left the Sands Macau, and it is an absolute pleasure but no surprise to see the continued success he is having. Luis would be a great addition to any organization or restaurant and I would have no hesitation in recommending Luis, or rehiring him should the opportunity present itself.  ", "recommendations/3/name": "L D R.", "recommendations/3/subtitle": "Sous Chef", "recommendations/3/url": "https://www.linkedin.com/in/l-d-r-3104568a/", "recommendations/3/urn": "urn:li:fsd_profile:ACoAABLujzwBlU-EhXMD0KrGZX5B6V0YhHaAiyk", "recommendations/4/context": "Fabrice worked with Julieta on the same team", "recommendations/4/date": "October 23, 2012", "recommendations/4/description": "Julieta is a hard working and well organized worker who prides herself in the quality of the work she produces. She is not afraid to spend long hours in order to meet her project deadlines. Julieta's strongest attribute is the pleasant nature in the way she deals with internal and external customers. \nJulieta is a resourceful worker who was a valuable member of the Team and made an immensely valuable contribution to the improvements of the look and feel of the property. \nI have worked alongside Julieta for many years and would have no hesitation in recommending her for any position. Her organizational, creative and design skills would make her an asset for anyone choosing to employ her.", "recommendations/4/name": "Julieta Pereira", "recommendations/4/subtitle": "Project Mngr | Design Mngr | Hospitality Development & Project Management | FF&E", "recommendations/4/url": "https://www.linkedin.com/in/julieta-pereira-6a980039/", "recommendations/4/urn": "urn:li:fsd_profile:ACoAAAggs-EBSEOcePXsZRMAx36pc_9CNz-MQS0", "recommendationsReceived/0/context": "Denisa reported directly to Fabrice", "recommendationsReceived/0/date": "April 7, 2026", "recommendationsReceived/0/description": "It has been both my pleasure and a privilege to work with Fabrice as General Manager aboard various Norwegian Cruise Line ships. Working under his leadership, I experienced firsthand his exceptional ability to guide, inspire, and motivate a diverse team. Fabrice combines strategic vision with practical expertise. He consistently creates an environment where every team member feels valued, encourages creative problem-solving, and emphasizes the importance of operational excellence. His approachable leadership style allows teams to address challenges confidently, and his feedback is always insightful, constructive, and delivered with genuine support.\nUnder Fabrice’s leadership, I witnessed remarkable results: improved team cohesion, more efficient workflow processes and enhanced guest satisfaction. He leads not only with knowledge and professionalism but also with integrity, empathy, and a deep commitment to the success of both staff and passengers. I would consider it an extreme privilege to work under his leadership again. I am confident that Fabrice will excel in any role, bringing the same dedication, leadership and inspiration that I had the privilege to experience firsthand.", "recommendationsReceived/0/name": "Denisa A.", "recommendationsReceived/0/subtitle": "Results-Driven Operations Leader | Revenue Optimization & Data-Driven Strategy | Cruise Industry Specialist | Delivering High-Profit, High-Volume Performance | Leading High-Performing Teams", "recommendationsReceived/0/url": "https://www.linkedin.com/in/denisa-a-231089366/", "recommendationsReceived/0/urn": "urn:li:fsd_profile:ACoAAFrHpgUBewS7bcfSgQ0xwxpBJNVIo_-K7CY", "recommendationsReceived/1/context": "Chad reported directly to Fabrice", "recommendationsReceived/1/date": "March 19, 2020", "recommendationsReceived/1/description": "It was fantastic to work with Fabrice at Sands Macao. His leadership and motivation positively influenced our team to meet financial and personal goals. He has a vast knowledge of wine and it was always a unique and educational experience putting together wine and food pairing menus. I would definitely work again with Fabrice if the opportunity arises in the future. ", "recommendationsReceived/1/name": "Chad Ogden", "recommendationsReceived/1/subtitle": "Director of Food and Beverage Operations", "recommendationsReceived/1/url": "https://www.linkedin.com/in/chadogden/", "recommendationsReceived/1/urn": "urn:li:fsd_profile:ACoAAAo5UJABXVHOSEzyr9qcGlrw4HSBR7GwgPc", "recommendationsReceived/2/context": "eddy worked with Fabrice on the same team", "recommendationsReceived/2/date": "May 29, 2019", "recommendationsReceived/2/description": "Had the privilege of working with Fabrice when he was Food @ Beverage Manager and later when he was promoted to Hotel Director for Saga Cruises.\nFabrice has an unfailing eye for detail ,innovation and an example for senior management and staff in maintaining and improving standards .\nHis engagement with staff was a major factor in improving the already very high repeat guest rate whilst at the same time mining new revenue streams.\n\n", "recommendationsReceived/2/name": "eddy denaeghel", "recommendationsReceived/2/subtitle": "Consultant", "recommendationsReceived/2/url": "https://www.linkedin.com/in/eddy-denaeghel-191a57105/", "recommendationsReceived/2/urn": "urn:li:fsd_profile:ACoAABqsjT0B5MBGeK8wfqTpiOX1oU_48pf1MPk", "recommendationsReceived/3/context": "Rhiannon worked with Fabrice on the same team", "recommendationsReceived/3/date": "May 28, 2019", "recommendationsReceived/3/description": "Fabrice is a highly skilled leader committed to excellence in hospitality.  He is a forward thinker who understands continuous improvement and in getting the basics right which allow him to take his teams to the next level.  I’d love to work with him again! ", "recommendationsReceived/3/name": "Rhiannon Bach", "recommendationsReceived/3/subtitle": "CMO | Casino Marketing · iGaming & Land-Based | VIP, Loyalty & Digital Acquisition | Macau · Australia · North America · Europe", "recommendationsReceived/3/url": "https://www.linkedin.com/in/rhiannonbach/", "recommendationsReceived/3/urn": "urn:li:fsd_profile:ACoAAAFLlOgBvR008DHm0TRJ_4l_L3Ubv-QL3IE", "recommendationsReceived/4/context": "Luis worked with Fabrice but they were at different companies", "recommendationsReceived/4/date": "December 19, 2018", "recommendationsReceived/4/description": "I have known Fabrice since February of 2012 where I worked with him in Macau as part of a Lean transformation at the Sands Hotel and Casino. As part of the lean transformation, Fabrice was one of 3 key people charged to provide 5-star service while expanding their operation by opening new properties of the same caliber.  In addition, he was challenged to do so while not hiring additional resources given a constraint by the local government.  This is where Fabrice would be an asset to any employer where his analytical skills, hospitality experience, work ethic and leadership qualities would be required.\n\nDuring the four years that I worked with Fabrice, not only did he embrace the philosophy of continuous improvement by driving the results, but also by supporting the changes in many other ways; resulting in the improved efficiency in the running of his department, but also in improved customer service levels. Subsequently the processes were adopted by sister properties. \nAs a result, other areas and properties began following the process which had been first established with Fabrice’s team which enabled growth and opening new properties while following the hiring constraints.  There are currently 5 properties that have visited and benchmarked Fabrice’s process of lean management and continuous improvements.\nI am certain that Fabrice will make a great impact within a new team and any organization in the same manner that he did in Macau.\n", "recommendationsReceived/4/name": "Luis Garcia", "recommendationsReceived/4/subtitle": "Multi-Lingual Lean Transformation Practitioner | TPS Coach | Global Industry Experience | Non Traditional Sectors", "recommendationsReceived/4/url": "https://www.linkedin.com/in/garcialuism/", "recommendationsReceived/4/urn": "urn:li:fsd_profile:ACoAAAId-yABizeE9gjculyo00vZcwBa2ot4kSA", "recommendationsReceived/5/context": "L D worked with Fabrice on the same team", "recommendationsReceived/5/date": "December 18, 2018", "recommendationsReceived/5/description": "Fabrice and I worked together at Sands Macau Hotel for two and half years. Although I did not report directly to him, we worked very closely together during my period as Chef de Cuisine for Copa Steakhouse. \n\nI thoroughly enjoyed my time working with Mr. De Cotte and came to know him as a truly valuable asset to absolutely any team. He is honest, dependable, and incredibly hard-working. His knowledge of Food and Beverage and expertise in Hotel Management was a huge advantage to our entire team. He put this skillset to work in order to achieve not only the goals of the company, but those departmental objectives that Fabrice set for the continuous improvements and growth of the F&B department. \n\nAlong with his undeniable talent, Fabrice has always been an absolute joy to work with. Together with the restaurant manager, we collaborated very closely in running special lifestyle events in the restaurant, as well as in driving the improvements that led to numerous Awards & Accolades.  He is a true team player, and always manages to foster positive discussions and brings the best out of his employees.\n\nWithout a doubt, I confidently recommend Fabrice to join any team or organization. As a dedicated and knowledgeable Manager and an all-around great person, I know that he will be a beneficial addition to any organization.\n\nBest Regards \n\nLuis Rojas ", "recommendationsReceived/5/name": "L D R.", "recommendationsReceived/5/subtitle": "Sous Chef", "recommendationsReceived/5/url": "https://www.linkedin.com/in/l-d-r-3104568a/", "recommendationsReceived/5/urn": "urn:li:fsd_profile:ACoAABLujzwBlU-EhXMD0KrGZX5B6V0YhHaAiyk", "recommendationsReceived/6/context": "Pedro reported directly to Fabrice", "recommendationsReceived/6/date": "December 16, 2015", "recommendationsReceived/6/description": "I worked with Fabrice for two years as his Assistant Manager for Food and Beverage at the Sands Macau Hotel. \nDuring this time I had the pleasure to learn from one of the most knowledgeable professionals I’ve meet in F&B, covering all areas from service side, service standards to restaurant management; to the kitchen side, from kitchen organization and hygiene and safety, to product knowledge, preparation and presentation.\nAs a hospitality professional, Fabrice has over twenty years of experience in different areas of hospitality service. That translates into a very well trained and keen eye for detail, knowing how to build and nurture relationships with his teams and his customers and a constant demand for high level of standards in all areas of his operations.\nFabrice consistently seeks improvement for himself and for his projects. He has outstanding work ethics and understands and constantly strives for achieving his business goals and company objectives.\nFor these reasons I have no doubt on recommending Fabrice and I am sure he will be a major asset for any company and project he sets his mind to.", "recommendationsReceived/6/name": "Pedro Sanches", "recommendationsReceived/6/subtitle": "Luxury Hospitality Executive ✪ Rooms & General Management", "recommendationsReceived/6/url": "https://www.linkedin.com/in/pedro-sanches-hospitalitypro/", "recommendationsReceived/6/urn": "urn:li:fsd_profile:ACoAAAvB-YwB1jLtVLKdTTZdcxHWJt0Ty_V67fI", "recommendationsReceived/7/context": "Nayib reported directly to Fabrice", "recommendationsReceived/7/date": "December 20, 2013", "recommendationsReceived/7/description": "Fabrice is a seasoned Director, with a measured and accurate Management style, people skills unmatched as per my work experience, and with a knowledge in his field of expertise that goes way beyond his scope, he comes from an F&B background that has took him all over the world and on a Fast Track to success implementing and opening several outlets and service Processes \n\nHis Extensive knowledge of Western and Asian Cuisine, overseeing a diverse Environment with high Contrast like the very trendy Award Winning Copa Steak House and the most popular and busy restaurant of all Sands China Properties, the Moonlight all Day Dining Restaurant with an Asian/Cantonese Cuisine offering catered by Fabrice with his team; a perfect East meet West Examples and sums up a Leader that perfectly understand the Culture and demand of his business", "recommendationsReceived/7/name": "Nayib H. Diaz", "recommendationsReceived/7/subtitle": "F&B Manager", "recommendationsReceived/7/url": "https://www.linkedin.com/in/nayib/", "recommendationsReceived/7/urn": "urn:li:fsd_profile:ACoAAAbOezYBrjSS1Qgp41gnhGxU8ElCHXoiSN0", "recommendationsReceived/8/context": "Julieta worked with Fabrice on the same team", "recommendationsReceived/8/date": "August 28, 2013", "recommendationsReceived/8/description": "Fabrice is an extremely dedicated professional with an extensive international F&B experience and knowledge. His knowledge and experience is built on hard work through ranks and in his constant seek for self-development which gives him a solid understanding of the business. His large experience in world-wide operating organizations known for their quick changing environments make him a flexible “quick-thinking” leader with a very strong organization and customer focus approach to strategies and leadership. He also possesses great people/social skills and is a motivating leader that takes on challenges with determination and a remarkable “Can-do” attitude. His experience as part of pre-opening teams in the set-up and startup of operations allied with his strong leadership would make him an asset to any operator looking to set up or improve the operational functions of a large scale organization. Having worked alongside with Fabrice for many years I would not hesitate in giving my recommendation.", "recommendationsReceived/8/name": "Julieta Pereira", "recommendationsReceived/8/subtitle": "Project Mngr | Design Mngr | Hospitality Development & Project Management | FF&E", "recommendationsReceived/8/url": "https://www.linkedin.com/in/julieta-pereira-6a980039/", "recommendationsReceived/8/urn": "urn:li:fsd_profile:ACoAAAggs-EBSEOcePXsZRMAx36pc_9CNz-MQS0", "recommendationsReceived/9/context": "Roy worked with Fabrice on the same team", "recommendationsReceived/9/date": "September 25, 2012", "recommendationsReceived/9/description": "I had the pleasure of working with Fabrice for around 11 years. Whether in the capacity of Food & Beverage Manager, or indeed Hotel Director, Fabrice showed total professionalism in his work and his relationship with colleagues.", "recommendationsReceived/9/name": "Roy Parkinson", "recommendationsReceived/9/subtitle": "Cruise Director at Saga Shipping", "recommendationsReceived/9/url": "https://www.linkedin.com/in/roy-parkinson-691bb015/", "recommendationsReceived/9/urn": "urn:li:fsd_profile:ACoAAAMz0s0BfcE-5O0I46pCP1jEHBnM8Im6bpQ", "recommendationsReceived/10/context": "NEIL was Fabrice's client", "recommendationsReceived/10/date": "August 6, 2012", "recommendationsReceived/10/description": "Having worked his way up through the ranks, proving himself competent & capable, Fabrice had become the F&B manager by the time I came to know him, thereafter taking over as Hotel Director on the SAGA Ruby.\nNot only does he have the demonstrable capabilities to accomplish his job requirements, he also has excellent interpersonal skills.\nI wish him well on his current career past.", "recommendationsReceived/10/name": "NEIL BUCKLAND", "recommendationsReceived/10/subtitle": "GENERAL MANAGER at RAPID SPORTS", "recommendationsReceived/10/url": "https://www.linkedin.com/in/neil-buckland-a3435638/", "recommendationsReceived/10/urn": "urn:li:fsd_